class Solution: def solve(self, blocks: list[int]) -> int: stack = []; for block in blocks: if not stack or block <= stack[-1] * 3: stack.append(block); else: i = stack.pop(); stack.append(block); return len(stack) + 1;

import sys
for _ in range(int(input())):
    blocks = list(map(int, input().split()))
    sol = Solution()
    print(sol.solve(blocks))
